package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.TaskDto; import com.evernorth.smartemp.service.TaskService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/tasks") @RequiredArgsConstructor public class TaskController{private final TaskService s;@GetMapping public ResponseEntity<List<TaskDto.Response>> list(){return ResponseEntity.ok(s.listAll());}@GetMapping("/employee/{employeeId}")public ResponseEntity<List<TaskDto.Response>> employee(@PathVariable Long employeeId){return ResponseEntity.ok(s.listByEmployee(employeeId));}@PostMapping public ResponseEntity<TaskDto.Response> create(@Valid@RequestBody TaskDto.Request r){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(r));}@PutMapping("/{id}")public ResponseEntity<TaskDto.Response> update(@PathVariable Long id,@Valid@RequestBody TaskDto.Request r){return ResponseEntity.ok(s.update(id,r));}@PatchMapping("/{id}/status")public ResponseEntity<TaskDto.Response> status(@PathVariable Long id,@RequestBody TaskDto.StatusUpdateRequest r){return ResponseEntity.ok(s.updateStatus(id,r));}@DeleteMapping("/{id}")public ResponseEntity<Void> delete(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
